import{G as e,c as t,b as o,ae as r}from"./chunks/framework.Cpb2nuHT.js";const h=JSON.parse('{"title":"为什么要使用双亲委派机制？","description":"","frontmatter":{"title":"为什么要使用双亲委派机制？","date":"2024-08-01T20:09:28.000Z","tags":["Java","JVM","双亲委派"],"author":"花木凋零成兰"},"headers":[],"relativePath":"MisNotes/为什么要使用双亲委派机制？.md","filePath":"MisNotes/为什么要使用双亲委派机制？.md","lastUpdated":1722516194000}'),s={name:"MisNotes/为什么要使用双亲委派机制？.md"};function _(d,a,i,n,l,c){return o(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1722542968000"},[...a[0]||(a[0]=[r('<h1 id="为什么要使用双亲委派机制" tabindex="-1">为什么要使用双亲委派机制？ <a class="header-anchor" href="#为什么要使用双亲委派机制" aria-label="Permalink to &quot;为什么要使用双亲委派机制？&quot;">​</a></h1><p>Java 虚拟机判断两个类是否为同一个类的依据是：类名是否相同且加载该类的加载器是否相同;</p><p>如果没有双亲委派机制, 同一个类可能会被多个类加载器加载, 如此即便是相同的类也可能会被识别为两个不同的类, 相互赋值时会出现问题;</p><p>双亲委派机制能够保证多加载器加载某个类时, 最终只有一个类加载器加载, 确保加载结果相同; 没有双亲委派机制, 假如用户编写一个名为 <code>java.lang.Object</code> 的类, 并放在程序的 ClassPath 中, 系统就会出现多个不同的 Object 类, 此时 Java 类型体系中基础行为会无法保证, 应用程序会变得一片混乱;</p><p>此外, 双亲委派加载机制可以保证核心类的安全, 当有人想替换核心类 <code>String.java</code> 时, 在双亲委派机制下, 核心类会被启动类加载器(<code>BootstrapClassLoader</code>)优先加载, 轮到其他类加载器再去加载时, 会跳过已经加载过的类, 所以双亲委派加载机制在一定程度上防止了危险代码的植入; 解决了类加载的安全问题;</p><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li><a href="https://www.cnblogs.com/woaiheniunai/p/15456537.html" target="_blank" rel="noreferrer">为什么要使用双亲委派机制？</a></li></ul>',7)])])}const f=e(s,[["render",_]]);export{h as __pageData,f as default};
